const config = $input.first().json;
const githubToken = $env.GITHUB_TOKEN;
if (!githubToken) throw new Error('Set GITHUB_TOKEN in n8n environment variables.');
if (!config.githubRepo || !config.githubRepo.includes('/')) throw new Error('Configuration.githubRepo must be owner/repo.');

const now = new Date();
const weekEnd = new Date(now);
const weekStart = new Date(now);
weekStart.setUTCDate(weekEnd.getUTCDate() - 7);
const since = weekStart.toISOString();
const until = weekEnd.toISOString();
const startDate = since.slice(0, 10);
const headers = {
  Accept: 'application/vnd.github+json',
  Authorization: `Bearer ${githubToken}`,
  'X-GitHub-Api-Version': '2022-11-28',
  'User-Agent': 'n8n-weekly-dev-summary'
};

async function githubJson(url) {
  const response = await fetch(url, { headers });
  if (!response.ok) {
    const text = await response.text();
    throw new Error(`GitHub API ${response.status} for ${url}: ${text}`);
  }
  return await response.json();
}

const encodedRepo = encodeURIComponent(config.githubRepo);
const commitsUrl = `https://api.github.com/repos/${config.githubRepo}/commits?since=${encodeURIComponent(since)}&until=${encodeURIComponent(until)}&per_page=100`;
const closedIssuesUrl = `https://api.github.com/search/issues?q=${encodedRepo}+is:issue+closed:>=${startDate}&per_page=50`;
const mergedPrsUrl = `https://api.github.com/search/issues?q=${encodedRepo}+is:pr+is:merged+merged:>=${startDate}&per_page=50`;

const [commits, closedIssues, mergedPrs] = await Promise.all([
  githubJson(commitsUrl),
  githubJson(closedIssuesUrl),
  githubJson(mergedPrsUrl)
]);

const activity = {
  repo: config.githubRepo,
  language: (config.language || 'EN').toUpperCase(),
  weekStart: since,
  weekEnd: until,
  commits: commits.map((commit) => ({
    sha: commit.sha?.slice(0, 7),
    message: commit.commit?.message?.split('\n')[0],
    author: commit.commit?.author?.name,
    url: commit.html_url
  })),
  closedIssues: closedIssues.items.map((issue) => ({
    number: issue.number,
    title: issue.title,
    author: issue.user?.login,
    url: issue.html_url
  })),
  mergedPrs: mergedPrs.items.map((pr) => ({
    number: pr.number,
    title: pr.title,
    author: pr.user?.login,
    url: pr.html_url
  }))
};

const prompt = `Write a concise weekly narrative development summary in ${activity.language === 'FR' ? 'French' : 'English'} for ${activity.repo}.\n\nTime window: ${activity.weekStart} to ${activity.weekEnd}.\n\nUse these sections: Overview, Highlights, Merged Pull Requests, Closed Issues, Notable Commits, Next Week Signals. Keep it useful for project stakeholders and avoid inventing facts.\n\nActivity JSON:\n${JSON.stringify(activity, null, 2)}`;

return [{ json: { ...config, ...activity, prompt } }];

const claude = $input.first().json;
const config = $('Configuration').first().json;
const summary = claude.content?.map((part) => part.text).filter(Boolean).join('\n\n') || 'Claude returned no text content.';
return [{
  json: {
    discordWebhookUrl: config.discordWebhookUrl,
    content: `**Weekly development summary for ${config.githubRepo}**\n\n${summary}`.slice(0, 1900)
  }
}];
